// ── Embedded template images (base64) ────────────────────────────────
const FRONT_B64 = "";
const BACK_B64  = "";

// Pre-load both template images
const frontImg = new Image();
const backImg  = new Image();
let imagesReady = 0;
frontImg.src = "data:image/png;base64," + FRONT_B64;
backImg.src  = "data:image/png;base64," + BACK_B64;
frontImg.onload = () => { imagesReady++; };
backImg.onload  = () => { imagesReady++; };

// ── Card dimensions (matches the template PNG) ────────────────────────
const W = 434;
const H = 669;

// ── Photo box position on front card ─────────────────────────────────
const PHOTO_BOX = { x: 108, y: 196, w: 216, h: 216 };

// ── Text field positions on FRONT card ───────────────────────────────
// x, y = where the value text starts (after the baked-in label)
const FRONT_FIELDS = [
  { key: "name",    x: 168, y: 427, size: 17 },
  { key: "class",   x: 165, y: 458, size: 17 },
  { key: "dob",     x: 210, y: 486, size: 17 },
  { key: "session", x: 225, y: 515, size: 17 },
  { key: "blood",   x: 284, y: 545, size: 17 },
];

// ── Text field positions on BACK card ────────────────────────────────
const BACK_FIELDS = [
  { key: "father_name",    x: 188, y: 128, size: 14 },
  { key: "mother_name",    x: 178, y: 157, size: 14 },
  { key: "address",        x: 38,  y: 200, size: 14, wrap: true, wrapWidth: 370 },
  { key: "father_contact", x: 205, y: 245, size: 14 },
  { key: "mother_contact", x: 198, y: 274, size: 14 },
];

// ── All card fields (for column mapper) ──────────────────────────────
const FIELD_KEYS = [
  { key: "name",           label: "Full Name" },
  { key: "class",          label: "Class" },
  { key: "dob",            label: "Date of Birth" },
  { key: "session",        label: "Session" },
  { key: "blood",          label: "Blood Group" },
  { key: "father_name",    label: "Father's Name" },
  { key: "mother_name",    label: "Mother's Name" },
  { key: "address",        label: "Residential Address" },
  { key: "father_contact", label: "Father's Contact" },
  { key: "mother_contact", label: "Mother's Contact" },
  { key: "photo",          label: "Photo Filename" },
];

// ── Auto-mapping guesses for common column names ──────────────────────
const AUTO_MAP = {
  name:           ["name", "full name", "student name", "child name"],
  class:          ["class", "grade", "section", "class name"],
  dob:            ["dob", "date of birth", "birthdate", "birth date", "d.o.b", "d.o.b."],
  session:        ["session", "academic year", "year"],
  blood:          ["blood group", "blood", "blood type", "bloodgroup"],
  father_name:    ["father's name", "father name", "dad name", "fathername"],
  mother_name:    ["mother's name", "mother name", "mom name", "mothername"],
  address:        ["residential address", "address", "home address"],
  father_contact: ["father's contact", "father contact", "father phone", "father mobile"],
  mother_contact: ["mother's contact", "mother contact", "mother phone", "mother mobile"],
  photo:          ["photo", "photo filename", "image", "picture", "filename"],
};

// ── App state ─────────────────────────────────────────────────────────
let excelHeaders  = [];
let students      = [];       // raw rows from Excel
let photoMap      = {};       // filename (lowercase) → dataURL
let mappedData    = [];       // [{name, class, dob, ...}, ...]
let renderedCards = [];       // [{name, safeName, frontDataURL, backDataURL}]
let previewIndex  = 0;

// ═══════════════════════════════════════════════════════════════════════
// STEP 1 — Excel upload
// ═══════════════════════════════════════════════════════════════════════

function handleExcel(input) {
  const file = input.files[0];
  if (!file) return;

  const reader = new FileReader();
  reader.onload = (e) => {
    try {
      const wb   = XLSX.read(e.target.result, { type: "array" });
      const ws   = wb.Sheets[wb.SheetNames[0]];
      const rows = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" });

      if (rows.length < 2) throw new Error("Sheet appears empty.");

      excelHeaders = rows[0].map((h) => String(h).trim());
      students     = rows.slice(1).filter((r) => r.some((c) => c !== ""));

      showStatus("xlStatus", `✅ ${students.length} students loaded from "${file.name}"`, "ok");
      document.getElementById("step1").classList.add("done");
      buildColumnMapper();
      updateStudentList();
      checkReady();
    } catch (err) {
      showStatus("xlStatus", `❌ Error: ${err.message}`, "error");
    }
  };
  reader.readAsArrayBuffer(file);
}

// Build the column mapping UI
function buildColumnMapper() {
  const wrap = document.getElementById("colMapWrap");
  const map  = document.getElementById("colMap");
  wrap.style.display = "block";

  // Header row
  map.innerHTML = `
    <div class="col-header">CARD FIELD</div>
    <div></div>
    <div class="col-header">YOUR EXCEL COLUMN</div>
  `;

  for (const field of FIELD_KEYS) {
    const best = autoGuess(field.key);
    map.innerHTML += `
      <div class="field-label">${field.label}</div>
      <div class="arrow">→</div>
      <select id="map_${field.key}" onchange="updateMappedData()">
        <option value="">— skip —</option>
        ${excelHeaders
          .map((h, i) => `<option value="${i}" ${i === best ? "selected" : ""}>${h}</option>`)
          .join("")}
      </select>
    `;
  }

  updateMappedData();
}

// Try to auto-detect which Excel column matches each field
function autoGuess(key) {
  const guesses = AUTO_MAP[key] || [];
  for (let i = 0; i < excelHeaders.length; i++) {
    const h = excelHeaders[i].toLowerCase().trim();
    if (guesses.includes(h)) return i;
  }
  return -1;
}

// Re-read the mapping dropdowns and rebuild mappedData
function updateMappedData() {
  mappedData = students.map((row) => {
    const obj = {};
    for (const field of FIELD_KEYS) {
      const sel = document.getElementById(`map_${field.key}`);
      const idx = sel ? parseInt(sel.value) : NaN;
      obj[field.key] = !isNaN(idx) && idx >= 0 ? String(row[idx] || "").trim() : "";
    }
    return obj;
  });
  updateStudentList();
}

// ═══════════════════════════════════════════════════════════════════════
// STEP 2 — Photo upload
// ═══════════════════════════════════════════════════════════════════════

function handlePhotos(input) {
  const files = Array.from(input.files);
  photoMap = {};

  const promises = files.map(
    (f) =>
      new Promise((res) => {
        const reader = new FileReader();
        reader.onload = (e) => {
          photoMap[f.name.toLowerCase()] = e.target.result;
          res();
        };
        reader.readAsDataURL(f);
      })
  );

  Promise.all(promises).then(() => {
    showStatus("photoStatus", `✅ ${files.length} photo(s) uploaded`, "ok");
    document.getElementById("step2").classList.add("done");
    updateStudentList();
    checkReady();
  });
}

// ═══════════════════════════════════════════════════════════════════════
// STEP 3 — Student list, generate, preview, download
// ═══════════════════════════════════════════════════════════════════════

function updateStudentList() {
  if (!mappedData.length) return;

  const wrap = document.getElementById("studentListWrap");
  const list = document.getElementById("studentList");
  wrap.style.display = "block";

  list.innerHTML = mappedData
    .map((s, i) => {
      const photoFile  = s.photo ? s.photo.toLowerCase() : "";
      const photoFound = photoFile && photoMap[photoFile];
      return `
        <div class="student-row">
          <span class="snum">${i + 1}</span>
          <span class="sname">${s.name || "(no name)"}</span>
          <span class="sphoto ${photoFound ? "found" : ""}">
            ${photoFound ? "📷 photo ✓" : photoFile ? "⚠ photo missing" : "no photo"}
          </span>
        </div>`;
    })
    .join("");
}

function checkReady() {
  document.getElementById("genBtn").disabled = students.length === 0;
}

// ── Generate all cards ────────────────────────────────────────────────

async function generateAll() {
  updateMappedData();

  const btn = document.getElementById("genBtn");
  btn.disabled    = true;
  btn.textContent = "⏳ Generating...";

  const pw = document.getElementById("progressWrap");
  pw.style.display = "block";

  renderedCards = [];
  const total   = mappedData.length;

  // Wait for template images
  await waitForImages();
  // Wait for web fonts (Poppins)
  await document.fonts.ready;

  for (let i = 0; i < total; i++) {
    const s   = mappedData[i];
    const pct = Math.round((i / total) * 100);

    document.getElementById("progressBar").style.width  = pct + "%";
    document.getElementById("progressLabel").textContent =
      `Generating ${i + 1} of ${total}: ${s.name || "student"}`;

    // Load the student's photo (if any)
    const photoKey = s.photo ? s.photo.toLowerCase() : "";
    const photoURL = photoMap[photoKey] || null;
    const photoImg = await loadImage(photoURL);

    // Draw front
    const frontCanvas = makeCanvas();
    drawFront(frontCanvas.getContext("2d"), s, photoImg);

    // Draw back
    const backCanvas = makeCanvas();
    drawBack(backCanvas.getContext("2d"), s);

    const safeName = (s.name || `student_${i + 1}`).replace(/\s+/g, "_");
    renderedCards.push({
      name:          s.name || `student_${i + 1}`,
      safeName,
      frontDataURL:  frontCanvas.toDataURL("image/png"),
      backDataURL:   backCanvas.toDataURL("image/png"),
    });

    // Let the browser breathe between cards
    await sleep(10);
  }

  document.getElementById("progressBar").style.width   = "100%";
  document.getElementById("progressLabel").textContent = `✅ ${total} card(s) ready!`;

  btn.disabled    = false;
  btn.textContent = "🔄 Regenerate";

  previewIndex = 0;
  showPreview();
}

// ── Card drawing ──────────────────────────────────────────────────────

function drawFront(ctx, student, photoImg) {
  // Draw template background
  ctx.drawImage(frontImg, 0, 0, W, H);

  // Paste student photo into the orange frame
  if (photoImg) {
    const b     = PHOTO_BOX;
    const scale = Math.max(b.w / photoImg.width, b.h / photoImg.height);
    const sw    = photoImg.width  * scale;
    const sh    = photoImg.height * scale;
    const sx    = b.x - (sw - b.w) / 2;
    const sy    = b.y - (sh - b.h) / 2;

    ctx.save();
    ctx.beginPath();
    ctx.rect(b.x, b.y, b.w, b.h);
    ctx.clip();
    ctx.drawImage(photoImg, sx, sy, sw, sh);
    ctx.restore();
  }

  // Draw value text
  ctx.fillStyle    = "#3c3c3c";
  ctx.textBaseline = "top";

  for (const f of FRONT_FIELDS) {
    ctx.font = `600 ${f.size}px Poppins, sans-serif`;
    ctx.fillText(student[f.key] || "", f.x, f.y);
  }
}

function drawBack(ctx, student) {
  ctx.drawImage(backImg, 0, 0, W, H);

  ctx.fillStyle    = "#323232";
  ctx.textBaseline = "top";

  for (const f of BACK_FIELDS) {
    ctx.font = `500 ${f.size}px Poppins, sans-serif`;
    if (f.wrap) {
      wrapText(ctx, student[f.key] || "", f.x, f.y, f.wrapWidth, f.size + 4);
    } else {
      ctx.fillText(student[f.key] || "", f.x, f.y);
    }
  }
}

// ── Preview ───────────────────────────────────────────────────────────

function showPreview() {
  document.getElementById("previewSection").style.display = "block";

  const card = renderedCards[previewIndex];
  document.getElementById("navLabel").textContent =
    `${card.name} (${previewIndex + 1} of ${renderedCards.length})`;

  document.getElementById("prevBtn").disabled = previewIndex === 0;
  document.getElementById("nextBtn").disabled = previewIndex === renderedCards.length - 1;

  drawOnCanvas("prevFront", card.frontDataURL);
  drawOnCanvas("prevBack",  card.backDataURL);
}

function previewNav(dir) {
  previewIndex = Math.max(0, Math.min(renderedCards.length - 1, previewIndex + dir));
  showPreview();
}

function drawOnCanvas(canvasId, dataURL) {
  const canvas = document.getElementById(canvasId);
  const ctx    = canvas.getContext("2d");
  const img    = new Image();
  img.onload   = () => ctx.drawImage(img, 0, 0, 434, 669);
  img.src      = dataURL;
}

// ── Download ZIP ──────────────────────────────────────────────────────

async function downloadZip() {
  if (!renderedCards.length) return;

  const btn      = document.getElementById("dlAllBtn");
  btn.textContent = "⏳ Creating ZIP...";
  btn.disabled   = true;

  const zip    = new JSZip();
  const folder = zip.folder("koala_id_cards");

  for (const card of renderedCards) {
    folder.file(`${card.safeName}_front.png`, card.frontDataURL.split(",")[1], { base64: true });
    folder.file(`${card.safeName}_back.png`,  card.backDataURL.split(",")[1],  { base64: true });
  }

  const blob = await zip.generateAsync({ type: "blob" });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement("a");
  a.href     = url;
  a.download = "koala_id_cards.zip";
  a.click();
  URL.revokeObjectURL(url);

  btn.textContent = "⬇ Download All Cards as ZIP";
  btn.disabled   = false;
}

// ═══════════════════════════════════════════════════════════════════════
// UTILITIES
// ═══════════════════════════════════════════════════════════════════════

function makeCanvas() {
  const c = document.createElement("canvas");
  c.width  = W;
  c.height = H;
  return c;
}

function loadImage(dataURL) {
  return new Promise((res) => {
    if (!dataURL) return res(null);
    const img    = new Image();
    img.onload   = () => res(img);
    img.onerror  = () => res(null);
    img.src      = dataURL;
  });
}

function waitForImages() {
  return new Promise((res) => {
    if (imagesReady >= 2) return res();
    const t = setInterval(() => {
      if (imagesReady >= 2) { clearInterval(t); res(); }
    }, 100);
  });
}

function sleep(ms) {
  return new Promise((res) => setTimeout(res, ms));
}

function wrapText(ctx, text, x, y, maxWidth, lineHeight) {
  if (!text) return;
  const words = String(text).split(" ");
  let line  = "";
  let lineY = y;

  for (const word of words) {
    const test = line ? line + " " + word : word;
    if (ctx.measureText(test).width > maxWidth && line) {
      ctx.fillText(line, x, lineY);
      line  = word;
      lineY += lineHeight;
    } else {
      line = test;
    }
  }
  if (line) ctx.fillText(line, x, lineY);
}

function showStatus(id, msg, type) {
  document.getElementById(id).innerHTML =
    `<div class="status-tag ${type}">${msg}</div>`;
}